import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { getIssues } from "../../api/issuesApi";

function Feed() {
  const [issues, setIssues] = useState([]);
  const navigate = useNavigate();

  useEffect(() => {
    getIssues()
      .then(res => setIssues(res.data))
      .catch(err => console.error(err));
  }, []);

  return (
    <div>
      <h1>Voter Feed</h1>

      {/* Top action buttons */}
      <div style={{ marginBottom: "20px" }}>
        <button onClick={() => navigate("/voter/raise-issue")}>
          Raise Issue
        </button>

        <button onClick={() => navigate("/voter/elections")}>
          Elections
        </button>
      </div>

      <hr />

      <h3>Issues in Your Constituency</h3>

      {issues.length === 0 && <p>No issues raised yet</p>}

      {issues.map(issue => (
        <div
          key={issue.id}
          style={{
            border: "1px solid #ccc",
            padding: "10px",
            marginBottom: "10px"
          }}
        >
          <p>{issue.description}</p>
          <small>Status: {issue.status}</small>
        </div>
      ))}
    </div>
  );
}

export default Feed;
